#!/usr/bin/env python3
"""Run `pnpm lint` before any `git commit`; block the commit if lint fails.

Enforces the CLAUDE.md convention: "Run lint with `pnpm lint` before committing."
"""
import json, os, re, subprocess, sys

GIT_COMMIT = re.compile(r"\bgit\s+commit\b")


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not GIT_COMMIT.search(cmd):
        return 0
    cwd = ev.get("cwd") or os.environ.get("CLAUDE_PROJECT_DIR") or os.getcwd()
    try:
        r = subprocess.run(
            ["pnpm", "lint"],
            cwd=cwd,
            capture_output=True,
            text=True,
            timeout=90,
        )
    except Exception as e:
        print(
            f"BLOCKING: could not run `pnpm lint` ({e}). Fix the lint setup, then retry the commit. Do not skip.",
            file=sys.stderr,
        )
        return 2
    if r.returncode != 0:
        print(
            "BLOCKING: `pnpm lint` failed. Fix each lint error, then retry the commit. Do not bypass with --no-verify.",
            file=sys.stderr,
        )
        tail = (r.stdout + r.stderr).strip().splitlines()[-20:]
        for line in tail:
            print(f"  {line}", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block shell commands that read .env / .env.* files (secrets live in .env.local)."""
import json, re, sys

READ_CMDS = (
    r"(?:cat|tac|head|tail|less|more|view|nl|sed|awk|grep|egrep|fgrep|rg|"
    r"od|xxd|hexdump|strings|file|dd|source)"
)
ENV_FILE = r"(?<![\w.])\.env(?:\.[\w.-]+)?(?![\w.])"

PATTERNS = [
    re.compile(rf"<\s*\S*{ENV_FILE}"),
    re.compile(rf"\b{READ_CMDS}\b[^|;&\n]*?{ENV_FILE}"),
]

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    for pat in PATTERNS:
        if pat.search(cmd):
            print(
                "BLOCKING: shell reads of .env files are not allowed (secrets live in .env.local). "
                "Do not cat/grep/source .env files. If you need a value, ask the user.",
                file=sys.stderr,
            )
            return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

