#!/usr/bin/env python3
"""self-improving-claude/no-unbounded-recursion

PostToolUse guard: flags newly-written Python self-recursive functions that
have no visible depth bound. Reason: walk_tree was refactored from iterative
to recursive and overflowed on a 2000-leaf tree.
"""
import ast
import json
import sys


def find_self_recursive(source):
    try:
        tree = ast.parse(source)
    except SyntaxError:
        return {}
    out = {}
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            for sub in ast.walk(node):
                if isinstance(sub, ast.Call):
                    f = sub.func
                    if isinstance(f, ast.Name) and f.id == node.name:
                        out[node.name] = node
                        break
                    if isinstance(f, ast.Attribute) and f.attr == node.name:
                        out[node.name] = node
                        break
    return out


def has_depth_guard(node):
    args = list(node.args.args) + list(getattr(node.args, "kwonlyargs", []))
    for a in args:
        n = a.arg.lower()
        if any(k in n for k in ("depth", "level", "limit", "remaining", "budget")):
            return True
    for sub in ast.walk(node):
        if isinstance(sub, ast.Call):
            f = sub.func
            if isinstance(f, ast.Attribute) and f.attr == "setrecursionlimit":
                return True
    return False


def changed_text(tool, inp):
    if tool == "Write":
        return inp.get("content", "") or ""
    if tool == "Edit":
        return inp.get("new_string", "") or ""
    if tool == "MultiEdit":
        return "\n".join((e.get("new_string", "") or "") for e in (inp.get("edits") or []))
    return ""


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool not in ("Edit", "Write", "MultiEdit"):
        return 0
    file_path = inp.get("file_path", "") or ""
    if not file_path.endswith(".py"):
        return 0
    try:
        with open(file_path, "r", encoding="utf-8") as f:
            source = f.read()
    except Exception:
        return 0
    recursive = find_self_recursive(source)
    if not recursive:
        return 0
    delta = changed_text(tool, inp)
    flagged = []
    for fname, node in recursive.items():
        if f"def {fname}" not in delta:
            continue
        if has_depth_guard(node):
            continue
        flagged.append(fname)
    if not flagged:
        return 0
    names = ", ".join(sorted(set(flagged)))
    msg = (
        f"BLOCKING: {file_path} now defines self-recursive function(s) without a visible depth bound: {names}. "
        "Python's default recursion limit (~1000) overflows on realistic inputs; "
        "walk_tree already hit this on a 2000-leaf tree. "
        "REQUIRED FOLLOW-UP: Do not stop and do not ask the user. "
        "Fix each function listed by one of: "
        "(a) rewrite iteratively using an explicit stack/queue; "
        "(b) add an explicit depth/limit parameter and raise before exceeding it; "
        "(c) call sys.setrecursionlimit() at module scope with a comment justifying the bound. "
        "Re-edit the file to apply the fix before continuing."
    )
    print(msg, file=sys.stderr)
    return 2


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Write/Edit/MultiEdit on a .py file, run `ruff format` + `ruff check --fix`
in place, then surface any remaining lint errors as imperative stderr."""
import json
import subprocess
import sys


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Write", "Edit", "MultiEdit"):
        return 0
    path = (ev.get("tool_input") or {}).get("file_path", "")
    if not path.endswith(".py"):
        return 0

    try:
        subprocess.run(["ruff", "format", path], capture_output=True, timeout=10)
        subprocess.run(["ruff", "check", "--fix", path], capture_output=True, timeout=10)
        r = subprocess.run(
            ["ruff", "check", path], capture_output=True, text=True, timeout=10
        )
    except FileNotFoundError:
        return 0
    except Exception:
        return 0

    if r.returncode != 0:
        print(f"BLOCKING: ruff check reports issues in {path}:", file=sys.stderr)
        if r.stdout:
            print(r.stdout, file=sys.stderr)
        if r.stderr:
            print(r.stderr, file=sys.stderr)
        print("Fix each, then proceed. Do not stop. Do not ask.", file=sys.stderr)
        return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Edit/MultiEdit of an exported identifier or its string value -> grep stale refs."""
import json, os, re, subprocess, sys

EXPORT_ID = re.compile(r"export\s+(?:const|let|var|function|class|interface|type|enum)\s+(\w+)")
EXPORT_VAL = re.compile(r"""export\s+(?:const|let|var)\s+(\w+)\s*(?::[^=]+)?=\s*(['\"`])([^'\"`\n]{2,})\2""")

def grep(needle, root):
    try:
        r = subprocess.run(
            ["grep", "-rnF", "--include=*.ts", "--include=*.tsx", "--include=*.js",
             "--include=*.jsx", "--include=*.mjs", "--include=*.cjs", needle, root],
            capture_output=True, text=True, timeout=8,
        )
        return [l for l in r.stdout.splitlines() if l][:25]
    except Exception:
        return []

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [{"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}]
    root = os.environ.get("CLAUDE_PROJECT_DIR") or os.getcwd()
    findings = []
    for e in edits:
        old, new = e.get("old_string", ""), e.get("new_string", "")
        ov, nv = EXPORT_VAL.search(old), EXPORT_VAL.search(new)
        if ov and nv and ov.group(1) == nv.group(1) and ov.group(3) != nv.group(3):
            hits = grep(ov.group(3), root)
            if hits:
                findings.append((f"value '{ov.group(3)}' (now '{nv.group(3)}') of exported `{ov.group(1)}`", hits))
            continue
        oi, ni = EXPORT_ID.search(old), EXPORT_ID.search(new)
        if oi and ni and oi.group(1) != ni.group(1) and len(oi.group(1)) >= 3:
            hits = grep(oi.group(1), root)
            if hits:
                findings.append((f"identifier `{oi.group(1)}` (now `{ni.group(1)}`)", hits))
    if not findings:
        return 0
    print("REQUIRED FOLLOW-UP: exported symbol changed. Stale references remain:\n", file=sys.stderr)
    for label, hits in findings:
        print(f"--- {label} ---", file=sys.stderr)
        for h in hits:
            print(f"  {h}", file=sys.stderr)
    print("\nFix each reference above to match the new declaration. Do not stop. Do not ask.", file=sys.stderr)
    return 2

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block Write/Edit/MultiEdit that embeds an API-key or other secret literal.
CLAUDE.md requires secrets come from process.env, never hardcoded in source."""
import json, re, sys

PATTERNS = [
    (re.compile(r"sk-(?:proj-)?[A-Za-z0-9_-]{20,}"), "OpenAI API key"),
    (re.compile(r"sk-ant-[A-Za-z0-9_-]{20,}"), "Anthropic API key"),
    (re.compile(r"AKIA[0-9A-Z]{16}"), "AWS access key id"),
    (re.compile(r"ASIA[0-9A-Z]{16}"), "AWS session key id"),
    (re.compile(r"ghp_[A-Za-z0-9]{36}"), "GitHub personal access token"),
    (re.compile(r"github_pat_[A-Za-z0-9_]{20,}"), "GitHub fine-grained token"),
    (re.compile(r"xox[abprs]-[A-Za-z0-9-]{10,}"), "Slack token"),
    (re.compile(r"AIza[0-9A-Za-z_-]{35}"), "Google API key"),
    (re.compile(r"-----BEGIN (?:RSA |EC |OPENSSH |DSA |PGP )?PRIVATE KEY-----"), "private key block"),
]


def scan(text):
    for pat, label in PATTERNS:
        m = pat.search(text or "")
        if m:
            return label, m.group(0)[:10] + "..."
    return None


def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    if tool not in ("Write", "Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    chunks = []
    if tool == "Write":
        chunks.append(inp.get("content", ""))
    elif tool == "Edit":
        chunks.append(inp.get("new_string", ""))
    elif tool == "MultiEdit":
        for e in inp.get("edits") or []:
            chunks.append(e.get("new_string", ""))
    for c in chunks:
        hit = scan(c)
        if hit:
            label, preview = hit
            path = inp.get("file_path", "<unknown>")
            print(f"BLOCKING: refusing to write a likely {label} ({preview}) into {path}.", file=sys.stderr)
            print("Secrets must come from process.env per CLAUDE.md. Replace the literal with process.env.<VAR_NAME>, document the variable in .env.example, then retry. Do not retry with the literal value.", file=sys.stderr)
            return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""Block `git commit` when the subject line is longer than 72 chars
(team convention: short imperative subject, details in the body)."""
import json, re, shlex, sys

SUBJECT_MAX = 72
HEREDOC_RE = re.compile(r"<<-?\s*['\"]?(\w+)['\"]?\s*\n(.*?)\n\1\b", re.DOTALL)
GIT_COMMIT_RE = re.compile(r"\bgit\s+commit\b")


def extract_messages(cmd: str) -> list[str]:
    messages: list[str] = []
    cleaned = cmd
    for m in HEREDOC_RE.finditer(cmd):
        messages.append(m.group(2))
    cleaned = HEREDOC_RE.sub(" HEREDOC_BODY ", cleaned)
    try:
        tokens = shlex.split(cleaned, posix=True)
    except ValueError:
        return messages
    i = 0
    while i < len(tokens):
        tok = tokens[i]
        if tok in ("-m", "--message") and i + 1 < len(tokens):
            val = tokens[i + 1]
            if val and "HEREDOC_BODY" not in val and not val.startswith("$("):
                messages.append(val)
            i += 2
            continue
        if tok.startswith("--message="):
            messages.append(tok[len("--message="):])
        i += 1
    return messages


def main() -> int:
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") != "Bash":
        return 0
    cmd = (ev.get("tool_input") or {}).get("command", "")
    if not GIT_COMMIT_RE.search(cmd):
        return 0
    for msg in extract_messages(cmd):
        subject = msg.strip().split("\n", 1)[0].strip()
        if len(subject) > SUBJECT_MAX:
            print(
                f"BLOCKING: commit subject is {len(subject)} chars (max {SUBJECT_MAX}). "
                f"Team convention: short imperative subject, e.g. "
                f"'Refactor auth: extract token validation'. "
                f"Rewrite the subject to fit on one line; put any explanation in the body "
                f"after a blank line. Do not retry until the subject is shortened.",
                file=sys.stderr,
            )
            return 2
    return 0


if __name__ == "__main__":
    sys.exit(main())

