import json, sys, subprocess, shutil, os

LINTERS = [
    (["ruff", "check", "--select=F", "--no-fix"], "ruff"),
    (["pyflakes"], "pyflakes"),
    (["flake8", "--select=F"], "flake8"),
]

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}
    if tool not in ("Edit", "Write"):
        return 0
    path = inp.get("file_path", "")
    if not path.endswith(".py") or not os.path.isfile(path):
        return 0
    chosen = None
    for cmd_prefix, name in LINTERS:
        if shutil.which(cmd_prefix[0]):
            chosen = (cmd_prefix, name)
            break
    if not chosen:
        return 0
    cmd_prefix, name = chosen
    try:
        result = subprocess.run(cmd_prefix + [path], capture_output=True, text=True, timeout=15)
    except Exception:
        return 0
    if result.returncode == 0:
        return 0
    msg = (result.stdout or result.stderr).strip()
    if not msg:
        return 0
    print(
        f"BLOCKING: {name} flagged issues in {path}. "
        f"Fix each before continuing — do not claim the task is complete or move on until the file is clean:\n{msg}",
        file=sys.stderr,
    )
    return 2

if __name__ == "__main__":
    sys.exit(main())
